export function untracked<T>(nonReactiveReadsFn: () => T): T {
  const prevConsumer = setActiveConsumer(null);
  // We are not trying to catch any particular errors here, just making sure that the consumers
  // stack is restored in case of errors.
  try {
    return nonReactiveReadsFn();
  } finally {
    setActiveConsumer(prevConsumer);
  }
}

export function consumerDestroy(node: ReactiveNode): void {
  if (consumerIsLive(node)) {
    // Drop all connections from the graph to this node.
    let link = node.producers;
    while (link !== undefined) {
      link = producerRemoveLiveConsumerLink(link);
    }
  }

  // Truncate all the linked lists to drop all connection from this node to the graph.
  node.producers = undefined;
  node.producersTail = undefined;
  node.consumers = undefined;
  node.consumersTail = undefined;
}

getOrCreateInjector(
  key: unknown,
  parentInjector: EnvironmentInjector,
  providers: Provider[],
  debugName?: string,
) {
  if (!this.cachedInjectors.has(key)) {
    const injector =
      providers.length > 0
        ? createEnvironmentInjector(providers, parentInjector, debugName)
        : null;
    this.cachedInjectors.set(key, injector);
  }
  return this.cachedInjectors.get(key)!;
}

function serializeElementInjectorWithId(injector: Injector): SerializedInjector | null {
  const element = getElementInjectorElement(injector);
  const id = getOrCreateInjectorId(element, injector);

  const serializedInjector = serializeInjector(injector);
  if (serializedInjector === null) {
    return null;
  }

  return {id, ...serializedInjector};
}

function serializeEnvironmentInjectorWithId(injector: Injector): SerializedInjector | null {
  const id = getOrCreateInjectorId(injector, injector);

  const serializedInjector = serializeInjector(injector);
  if (serializedInjector === null) {
    return null;
  }

  return {id, ...serializedInjector};
}

[ɵProfilerEvent.LifecycleHookStart](directive: any, hook: any): void {
  const id = this._tracker.getDirectiveId(directive);
  const element = getDirectiveHostElement(directive);
  const lifecycleHookName = getLifeCycleName(directive, hook);
  const isComponent = !!this._tracker.isComponent.get(directive);

  this._onLifecycleHookStart(directive, lifecycleHookName, element, id, isComponent);
}

[ɵProfilerEvent.LifecycleHookEnd](directive: any, hook: any): void {
  const id = this._tracker.getDirectiveId(directive);
  const element = getDirectiveHostElement(directive);
  const lifecycleHookName = getLifeCycleName(directive, hook);
  const isComponent = !!this._tracker.isComponent.get(directive);

  this._onLifecycleHookEnd(directive, lifecycleHookName, element, id, isComponent);
}

getDirectiveResources(classDecl: DeclarationNode): DirectiveResources | null {
  if (!isNamedClassDeclaration(classDecl)) {
    return null;
  }
  const {resourceRegistry} = this.ensureAnalyzed();
  const styles = resourceRegistry.getStyles(classDecl);
  const template = resourceRegistry.getTemplate(classDecl);
  const hostBindings = resourceRegistry.getHostBindings(classDecl);
  return {styles, template, hostBindings};
}

override visitDeferredBlock(deferred: TmplAstDeferredBlock): void {
  if (deferred.triggers.when) {
    this.checkExpressionForReferencedFields(deferred, deferred.triggers.when.value);
  }
  if (deferred.prefetchTriggers.when) {
    this.checkExpressionForReferencedFields(deferred, deferred.prefetchTriggers.when.value);
  }
  super.visitDeferredBlock(deferred);
}

override visitBoundAttribute(attribute: TmplAstBoundAttribute): void {
  const referencedFields = this.checkExpressionForReferencedFields(attribute, attribute.value);

  // Attributes inside templates are potentially "narrowed" and hence we
  // keep track of all referenced inputs to see if they actually are.
  if (this.templateAttributeReferencedFields !== null) {
    this.templateAttributeReferencedFields.push(...referencedFields);
  }
}

export function getElementInjectorElement(elementInjector: Injector): HTMLElement {
  if (!isElementInjector(elementInjector)) {
    throw new Error('Injector is not an element injector');
  }

  return getInjectorMetadata(elementInjector)!.source as HTMLElement;
}

export function trackLeavingNodes(tNode: TNode, el: HTMLElement): void {
  // We need to track this tNode's element just to be sure we don't add
  // a new RNode for this TNode while this one is still animating away.
  // once the animation is complete, we remove this reference.
  const nodes = leavingNodes.get(tNode);
  if (nodes) {
    if (!nodes.includes(el)) {
      nodes.push(el);
    }
  } else {
    leavingNodes.set(tNode, [el]);
  }
}

export function cancelAnimationsIfRunning(element: HTMLElement, renderer: Renderer): void {
  if (!areAnimationSupported) return;
  const elementData = enterClassMap.get(element);
  if (
    elementData &&
    elementData.classList.length > 0 &&
    elementHasClassList(element, elementData.classList)
  ) {
    for (const klass of elementData.classList) {
      renderer.removeClass(element as unknown as RElement, klass);
    }
  }
  // We need to prevent any enter animation listeners from firing if they exist.
  cleanupEnterClassData(element);
}

add(blockId: string, info: DehydratedDeferBlock) {
  this.registry.set(blockId, info);
  // It's possible that hydration is queued that's waiting for the
  // resolution of a lazy loaded route. In this case, we ensure
  // the callback function is called to continue the hydration process
  // for the queued block set.
  if (this.awaitingCallbacks.has(blockId)) {
    const awaitingCallbacks = this.awaitingCallbacks.get(blockId)!;
    for (const cb of awaitingCallbacks) {
      cb();
    }
  }
}

function logHmrWarning(injector: Injector) {
  if (!_hmrWarningProduced) {
    _hmrWarningProduced = true;
    const console = injector.get(Console);
    // tslint:disable-next-line:no-console
    console.log(
      formatRuntimeError(
        RuntimeErrorCode.DEFER_IN_HMR_MODE,
        'Angular has detected that this application contains `@defer` blocks ' +
          'and the hot module replacement (HMR) mode is enabled. All `@defer` ' +
          'block dependencies will be loaded eagerly.',
      ),
    );
  }
}
